const items = $input.all();
const demande = items[0].json[0];
const grille = {
  'Polo brode': {price: 22, threshold: 20, discount: 10},
  'T-shirt flocage': {price: 18, threshold: 20, discount: 10},
  'Veste brodee': {price: 35, threshold: 10, discount: 8},
  'Casquette brodee': {price: 15, threshold: 20, discount: 5},
  'Tablier brode': {price: 20, threshold: 20, discount: 5},
  'Chemise brodee': {price: 28, threshold: 20, discount: 8},
  'Sac Tote bag': {price: 12, threshold: 30, discount: 5}
};
const produits = Array.isArray(demande.products) ? demande.products : [demande.products];
const qty = parseInt(demande.quantity) || 1;
let totalHT = 0;
const lignes = produits.map(p => {
  const info = grille[p] || {price: 20, threshold: 20, discount: 0};
  const remise = qty >= info.threshold ? info.discount : 0;
  const prixUnitaire = info.price;
  const totalLigne = qty * prixUnitaire * (1 - remise/100);
  totalHT += totalLigne;
  return {produit: p, quantite: qty, prix_unitaire: prixUnitaire, remise: remise, total: totalLigne.toFixed(2)};
});
const tva = 8.5;
const totalTVA = totalHT * tva / 100;
const totalTTC = totalHT + totalTVA;
const now = new Date();
const quoteNumber = 'DEV-' + now.getFullYear() + '-' + String(Math.floor(Math.random()*9000)+1000);
const expiry = new Date(now.getTime() + 30*24*60*60*1000);
return [{
  json: {
    demande,
    lignes,
    totalHT: totalHT.toFixed(2),
    totalTVA: totalTVA.toFixed(2),
    totalTTC: totalTTC.toFixed(2),
    quoteNumber,
    dateEmission: now.toLocaleDateString('fr-FR'),
    dateExpiration: expiry.toLocaleDateString('fr-FR')
  }
}];

const d = $input.first().json;
const lignesHTML = d.lignes.map(l => `<tr><td>${l.produit}</td><td>${l.quantite}</td><td>${l.prix_unitaire}€</td><td>${l.remise}%</td><td>${l.total}€</td></tr>`).join('');
const html = `<!DOCTYPE html><html><head><meta charset='UTF-8'><style>body{font-family:Arial,sans-serif;margin:40px;color:#333}h1{color:#E63946}table{width:100%;border-collapse:collapse;margin:20px 0}th,td{padding:10px;border:1px solid #ddd;text-align:left}th{background:#E63946;color:white}.total{font-size:1.2em;font-weight:bold}.footer{margin-top:40px;font-size:0.85em;color:#666}</style></head><body><div style='display:flex;justify-content:space-between'><div><h1>TENUEPRO</h1><p>Marquage textile professionnel<br>La Réunion — 0692 10 52 17<br>www.tenuepro.re</p></div><div style='text-align:right'><h2>DEVIS</h2><p>N° ${d.quoteNumber}<br>Date : ${d.dateEmission}<br>Valable jusqu'au : ${d.dateExpiration}</p></div></div><hr><h3>CLIENT</h3><p>${d.demande.contact_name}<br>${d.demande.company_name || ''}<br>SIRET : ${d.demande.siret || 'N/A'}<br>${d.demande.contact_email}<br>${d.demande.contact_phone || ''}</p><h3>DÉTAIL DU DEVIS</h3><table><thead><tr><th>Produit</th><th>Quantité</th><th>Prix unit. HT</th><th>Remise</th><th>Total HT</th></tr></thead><tbody>${lignesHTML}</tbody></table><div style='text-align:right'><p>Total HT : ${d.totalHT}€</p><p>TVA 8,5% : ${d.totalTVA}€</p><p class='total'>Total TTC : ${d.totalTTC}€</p></div><div class='footer'><p>Conditions : Acompte 50% à la commande. Solde à la livraison.<br>Délai de fabrication : 10-15 jours ouvrés après validation du BAT.<br>Devis valable 30 jours.</p></div></body></html>`;
return [{json: {html, ...d}}];
